1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	};
10	
11	interface Item {
12	  type: string;
13	}
14	
15	interface QuoteStep {
16	  op: "quote";
17	  items: Item[];
18	}
19	
20	interface Scenario {
21	  customer: { yearsWithMHPCO: number };
22	  steps: QuoteStep[];
23	}
24	
25	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
26	const COMPONENT_BASE = 25;
27	const BLOCK_SIZE = 3;
28	const BLOCK_BASE = 60;
29	
30	const componentBase = (count: number): number =>
31	  count === BLOCK_SIZE ? BLOCK_BASE : count * COMPONENT_BASE;
32	
33	const baseForType = (type: string, count: number): number =>
34	  COMPONENT_TYPES.has(type)
35	    ? componentBase(count)
36	    : (BASE_PREMIUMS[type] ?? 0) * count;
37	
38	const countByType = (items: Item[]): Map<string, number> =>
39	  items.reduce(
40	    (counts, item) =>
41	      counts.set(item.type, (counts.get(item.type) ?? 0) + 1),
42	    new Map<string, number>(),
43	  );
44	
45	const baseForItems = (items: Item[]): number =>
46	  [...countByType(items)].reduce(
47	    (total, [type, count]) => total + baseForType(type, count),
48	    0,
49	  );
50	
51	const priceQuote = (items: Item[]): { premium: number } => {
52	  const policyBase = baseForItems(items);
53	  const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_RATE;
54	  const premium = Math.ceil(
55	    policyBase + firstInsuranceSurcharge + PROCESSING_FEE,
56	  );
57	  return { premium };
58	};
59	
60	export const runScenario = (scenario: Scenario): { results: unknown[] } => {
61	  const results = scenario.steps.map((step) => priceQuote(step.items));
62	  return { results };
63	};
